const baseTags = {
  deviceId: 'gyh43',
  location: 'factory-1',
  hardwareVersion: '1.0.2',
  softwareVersion: '2.5.1',
};
const now = Date.now();

msg.payload = {
  bucket: "testBucket2",
  precision: "ms",
  data: [
    {
      measurement: "motor",
      tags: baseTags,
      fields: {
        left_speed: Math.random() * 12,
        left_power: Math.random() * 10,
        right_speed: Math.random() * 12,
        right_power: Math.random() * 20,
        avg_power: Math.random() * 12,
      },
      timestamp: now
    },
    {
      measurement: "battery",
      tags: baseTags,
      fields: {
        battery1_temp: Math.random() * 10,
        battery2_temp: Math.random() * 10,
        battery3_temp: Math.random() * 10,
        battery4_temp: Math.random() * 10,
        battery5_temp: Math.random() * 10,
        battery6_temp: Math.random() * 10,
      },
      timestamp: now
    }
  ]
};

return msg;

// msg.payload is temperature in °C
const t = Number(msg.payload);
msg.payload = t;

// pick your colors
msg.ui_update = msg.ui_update || {};
msg.ui_update.style = msg.ui_update.style || {};

// red if >= 60, otherwise normal
msg.ui_update.style.color = (t >= 60) ? "#ff0000" : "#00bcd4";      // text/needle color
msg.ui_update.style["--gauge-fill"] = (t >= 60) ? "#ff0000" : "#00bcd4"; // some widgets use CSS vars

return msg;

const THRESH = 60;

function randTemp() {
  let t = 20 + Math.random() * 50;  // 20..70
  return Math.round(t * 10) / 10;
}

// Create 6 temps
const temps = Array.from({ length: 6 }, randTemp);

// -------- Output 1: UI update (NO payload!) --------
// Note: when adjusting series settings, include ALL series each time. :contentReference[oaicite:2]{index=2}
const updateMsg = {
  ui_update: {
    chartOptions: {
      series: [
        { name: "Normal", type: "bar", stack: "temps", itemStyle: { color: "#00bcd4" } },
        { name: "Hot", type: "bar", stack: "temps", itemStyle: { color: "red" } }
      ]
    }
  }
};

// -------- Output 2: Data (Replace) --------
const payload = [];

for (let i = 0; i < 6; i++) {
  const label = `Battery ${i + 1}`;
  const t = temps[i];

  payload.push({
    series: "Normal",
    property: label,
    y: (t >= THRESH) ? null : t
  });

  payload.push({
    series: "Hot",
    property: label,
    y: (t >= THRESH) ? t : null
  });
}

const dataMsg = {
  action: "replace",
  payload
};

return [updateMsg, dataMsg];
